mapper.select:
SELECT d.id, d.webhook_config_id AS webhookId, d.event_id AS eventId, d.event_type AS eventType,
       d.status, d.retry_count AS retryCount, d.created_at AS createdAt,
       d.response_status AS responseStatus, d.failure_reason AS failureReason
FROM notification_deliveries d
WHERE d.deleted = FALSE
AND d.webhook_config_id = #{webhookId}
AND d.status = #{status}
ORDER BY d.created_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(1) FROM notification_deliveries d
WHERE d.deleted = FALSE
AND d.webhook_config_id = #{webhookId}
AND d.status = #{status}
